const { test, expect } = require('@playwright/test');

test('verify header navigation and routes', async ({ page }) => {
  await page.setViewportSize({ width: 375, height: 812 });
  await page.goto('http://localhost:3002/');

  // Verify Brand link
  const brandLink = page.getByRole('link', { name: 'okwasniewski' });
  await expect(brandLink).toHaveAttribute('href', '/');
  await brandLink.click();
  await expect(page).toHaveURL('http://localhost:3002/');

  // Verify Blog link
  const blogLink = page.getByRole('link', { name: 'blog', exact: true });
  await expect(blogLink).toHaveAttribute('href', '/blog');
  await blogLink.click();
  await expect(page).toHaveURL(/.*\/blog/);
  await page.goto('http://localhost:3002/');

  // Verify Portfolio link (Known issue: misspelled on home page)
  const portfolioLink = page.getByRole('link', { name: 'portfolio', exact: true });
  const portfolioHref = await portfolioLink.getAttribute('href');
  if (portfolioHref === '/portfoloi') {
    console.log('Detected bug: Portfolio link is misspelled as /portfoloi');
  }
  await portfolioLink.click();
  // Expecting /portfolio but might hit /portfoloi

  // Verify Videos link
  await page.goto('http://localhost:3002/');
  const videosLink = page.getByRole('link', { name: 'videos', exact: true });
  await expect(videosLink).toHaveAttribute('href', '/videos');
  await videosLink.click();
  await expect(page).toHaveURL(/.*\/videos/);

  // Verify Contact link (Known issue: misspelled on 404 page)
  await page.goto('http://localhost:3002/broken-link'); // Trigger 404
  const contactLink = page.getByRole('link', { name: 'contact', exact: true });
  const contactHref = await contactLink.getAttribute('href');
  if (contactHref === '/contcat') {
    console.log('Detected bug: Contact link is misspelled as /contcat on 404 page');
  }
});
